from matplotlib.patches import Rectanglefrom matplotlib.transforms import blended_transform_factoryfrom .utils import _format_axes, update_xlimfrom criresviz.plotting.style import (    ZORDER,    BOX_HEIGHT,    ORDER_TEXT_SIZE,    ALPHA,    COLORS,        )'''############################################################################################################################### Functions detectors ################################################################################################################################'''def _draw_detector(ax, detector, setting, legend=False):                transform = blended_transform_factory(        ax.transData,        ax.transAxes,    )        rectangle = Rectangle(        (detector.wavelength_min, 0),        detector.width,        BOX_HEIGHT,        facecolor=COLORS[setting][detector.number],        zorder=ZORDER["detector"],        transform=transform,        alpha=ALPHA,        label = setting if legend else None,    )    ax.add_patch(rectangle)    ##############################################    def _draw_order_label(ax, order):    detector = order.detector2        transform = blended_transform_factory(        ax.transData,        ax.transAxes,    )        ax.text(        detector.wavelength_min + detector.width / 2,        0.02,        str(order.number),        ha="center",        va="center",        transform=transform,        zorder=ZORDER["labels"],        fontsize=ORDER_TEXT_SIZE,    )    ##############################################    def _draw_setting(setting, ax):        update_xlim(ax=ax, wavelength_range=setting.wavelength_range)        _format_axes(ax)    i = 0    for order in setting:        _draw_order_label(ax, order)        for detector in order:            if(i==1): _draw_detector(ax, detector,setting.name, legend=True)            else: _draw_detector(ax,detector, setting.name)            i += 1                return ax